<?php require_once __DIR__.'/../includes/functions.php'; if(file_exists(__DIR__.'/../.env')){header('Location: /');exit;} $step=(int)($_GET['step']??1);$errors=[];$msg=''; $req=['PHP >= 8.0'=>version_compare(PHP_VERSION,'8.0.0','>='),'PDO'=>extension_loaded('pdo'),'PDO MySQL'=>extension_loaded('pdo_mysql'),'cURL'=>extension_loaded('curl'),'OpenSSL'=>extension_loaded('openssl'),'JSON'=>extension_loaded('json'),'Redis(可选)'=>extension_loaded('redis')];$allOk=!in_array(false,$req,true); if($step===2&&$_SERVER['REQUEST_METHOD']==='POST'){$dh=$_POST['db_host']??'127.0.0.1';$dp=$_POST['db_port']??'3306';$dn=$_POST['db_name']??'xinyu_status';$du=$_POST['db_user']??'root';$dpa=$_POST['db_pass']??'';try{$pdo=new PDO("mysql:host={$dh};port={$dp};charset=utf8mb4",$du,$dpa,[PDO::ATTR_ERRMODE=>PDO::ERRMODE_EXCEPTION]);$pdo->exec("CREATE DATABASE IF NOT EXISTS `{$dn}` DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci");$pdo->exec("USE `{$dn}`");$sc=file_get_contents(__DIR__.'/../schema.sql');$sts=array_filter(array_map('trim',explode(';',$sc)),fn($s)=>!empty($s)&&!preg_match('/^(CREATE DATABASE|USE\s+`)/i',$s));foreach($sts as $st)$pdo->exec($st);$msg='数据库初始化成功！';}catch(PDOException $e){$errors[]='数据库连接失败: '.$e->getMessage();}if(empty($errors)){$rh=$_POST['redis_host']??'127.0.0.1';$rp=$_POST['redis_port']??'6379';$rpa=$_POST['redis_pass']??'';file_put_contents(__DIR__.'/../.env',"# 应用配置\nAPP_TIMEZONE=Asia/Shanghai\n\n# 数据库配置\nDB_HOST={$dh}\nDB_PORT={$dp}\nDB_NAME={$dn}\nDB_USER={$du}\nDB_PASS={$dpa}\n\n# Redis配置\nREDIS_HOST={$rh}\nREDIS_PORT={$rp}\nREDIS_PASS={$rpa}\nREDIS_DB=0\n");$step=3;}} if($step===3&&$_SERVER['REQUEST_METHOD']==='POST'){$un=trim($_POST['username']??'');$pw=$_POST['password']??'';$em=trim($_POST['email']??'');if(empty($un)||empty($pw))$errors[]='用户名和密码不能为空。';elseif(strlen($pw)<6)$errors[]='密码至少6个字符。';else{require_once __DIR__.'/../config.php';require_once __DIR__.'/../includes/Database.php';require_once __DIR__.'/../includes/Auth.php';$db=Database::getInstance();$db->update('users',['username'=>$un,'password_hash'=>password_hash($pw,PASSWORD_BCRYPT,['cost'=>BCRYPT_COST]),'email'=>$em?:null],'username=?',['admin']);$msg='管理员账户创建成功！';$step=4;}} ?><!DOCTYPE html><html lang="zh-CN"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>安装向导 - XINYU Status Monitor</title><link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap" rel="stylesheet"><style>*{box-sizing:border-box;margin:0;padding:0}body{font-family:'Inter',sans-serif;background:#f0f2f5;min-height:100vh;display:flex;align-items:center;justify-content:center;padding:20px}.box{background:#fff;border-radius:16px;box-shadow:0 4px 24px rgba(0,0,0,.08);padding:40px;width:100%;max-width:640px}.box h1{font-size:1.5rem;color:#333;margin-bottom:24px;text-align:center}.steps{display:flex;margin-bottom:32px}.step{flex:1;text-align:center;padding:12px;font-size:.875rem;color:#999;border-bottom:3px solid #e5e7eb}.step.active{color:#667eea;border-color:#667eea;font-weight:600}.step.done{color:#2ecc71;border-color:#2ecc71}.fg{margin-bottom:16px}.fg label{display:block;font-size:.875rem;font-weight:500;color:#555;margin-bottom:6px}.fg input,.fg select{width:100%;padding:10px 14px;border:2px solid #e5e7eb;border-radius:8px;font-size:.9375rem;outline:none}.fg input:focus{border-color:#667eea}.btn{display:inline-block;padding:12px 32px;background:#667eea;color:#fff;border:none;border-radius:8px;font-size:1rem;font-weight:600;cursor:pointer;text-decoration:none}.btn:hover{opacity:.9}.btn2{background:#764ba2;margin-left:12px}.error{background:#fef2f2;color:#dc2626;padding:12px;border-radius:8px;margin-bottom:16px;font-size:.875rem}.success{background:#f0fdf4;color:#16a34a;padding:12px;border-radius:8px;margin-bottom:16px;font-size:.875rem}.req{display:flex;justify-content:space-between;padding:8px 0;border-bottom:1px solid #f0f0f0}.pass{color:#2ecc71}.fail{color:#e74c3c}.finish{text-align:center}.finish .icon{font-size:64px;margin-bottom:16px}</style></head><body><div class="box"><h1>XINYU Status Monitor 安装向导</h1><div class="steps"><div class="step <?php echo $step===1?'active':($step>1?'done':'');?>">环境检查</div><div class="step <?php echo $step===2?'active':($step>2?'done':'');?>">数据库配置</div><div class="step <?php echo $step===3?'active':($step>3?'done':'');?>">管理员设置</div><div class="step <?php echo $step===4?'active':'';?>">完成</div></div><?php if(!empty($errors)):foreach($errors as $e):?><div class="error"><?php echo e($e);?></div><?php endforeach;endif;?><?php if($msg):?><div class="success"><?php echo e($msg);?></div><?php endif;?><?php if($step===1):?><h3 style="margin-bottom:16px;">系统环境检查</h3><?php foreach($req as $n=>$m):?><div class="req"><span><?php echo $n;?></span><span class="<?php echo $m?'pass':'fail';?>"><?php echo $m?'✓':'✗';?></span></div><?php endforeach;?><div style="margin-top:24px;"><?php if($allOk):?><a href="?step=2" class="btn">下一步</a><?php else:?><p style="color:#e74c3c;">请先安装/启用缺失的扩展。</p><?php endif;?></div><?php elseif($step===2):?><form method="POST" action="?step=2"><h3 style="margin-bottom:16px;">数据库设置</h3><div class="fg"><label>数据库主机</label><input type="text" name="db_host" value="127.0.0.1" required></div><div class="fg"><label>端口</label><input type="text" name="db_port" value="3306" required></div><div class="fg"><label>数据库名</label><input type="text" name="db_name" value="xinyu_status" required></div><div class="fg"><label>用户名</label><input type="text" name="db_user" value="root" required></div><div class="fg"><label>密码</label><input type="password" name="db_pass"></div><h3 style="margin:20px 0 16px;">Redis设置 (可选)</h3><div class="fg"><label>Redis主机</label><input type="text" name="redis_host" value="127.0.0.1"></div><div class="fg"><label>端口</label><input type="text" name="redis_port" value="6379"></div><div class="fg"><label>密码</label><input type="password" name="redis_pass" placeholder="无密码请留空"></div><button type="submit" class="btn">下一步</button></form><?php elseif($step===3):?><form method="POST" action="?step=3"><h3 style="margin-bottom:16px;">设置管理员</h3><div class="fg"><label>用户名</label><input type="text" name="username" required></div><div class="fg"><label>邮箱</label><input type="email" name="email"></div><div class="fg"><label>密码</label><input type="password" name="password" required minlength="6"></div><button type="submit" class="btn">完成安装</button></form><?php elseif($step===4):?><div class="finish"><div class="icon">🎉</div><h2>安装完成！</h2><p style="margin:16px 0;color:#666;">XINYU Status Monitor 已成功安装。</p><p style="margin-bottom:16px;color:#999;font-size:.875rem;">请设置 cron 定时任务：<br><code style="background:#f0f0f0;padding:4px 8px;border-radius:4px;">* * * * * php <?php echo __DIR__;?>/../cron/check.php</code></p><a href="/" class="btn">查看状态页面</a><a href="/admin/" class="btn btn2">管理后台</a></div><?php endif;?></div></body></html>